import React from 'react';
import PropTypes from 'prop-types';
import { makeStyles } from '@material-ui/core/styles';
import Grid from '@material-ui/core/Grid';
import Paper from '@material-ui/core/Paper';
import Typography from '@material-ui/core/Typography';
import Link from '@material-ui/core/Link';
import {Avatar, Divider} from '@material-ui/core';
import ContactMailRoundedIcon from '@material-ui/icons/ContactMailRounded';
import LocationOnIcon from '@material-ui/icons/LocationOn';

const useStyles = makeStyles(theme => ({
    customAvatar:{
        margin: '0 auto',
        width: '150px',
        height: '150px',
    },
    customPaper:{
        paddingTop:theme.spacing(3),
    },
    sidebarBottom: {
        paddingBottom : theme.spacing(3),
        paddingLeft: theme.spacing(3),
        paddingTop: theme.spacing(3),
    },
    sideBarTitle:{
        paddingLeft: theme.spacing(3),
        paddingTop: theme.spacing(3),
    },
    sideBarDes:{
        paddingLeft: theme.spacing(3),
    },
    sideBarIcons:{
        verticalAlign: "middle",
    }
}));

export default function Sidebar(props) {
    const classes = useStyles();
    const {profile, social } = props;

    return (
        <Grid item xs={12} md={3}>
            <Paper elevation={0}  className={classes.customPaper}>
                <Avatar className={classes.customAvatar}/>
                <Typography variant="h6" gutterBottom className={classes.sideBarTitle}>
                    {profile.name}
                </Typography>
                <Typography gutterBottom className={classes.sideBarDes}>{profile.title}</Typography>
                <Typography gutterBottom className={classes.sideBarDes}>
                    <ContactMailRoundedIcon className={classes.sideBarIcons} fontSize="small"/> {profile.email}
                </Typography>
                <Typography gutterBottom className={classes.sideBarDes}>
                    <LocationOnIcon className={classes.sideBarIcons} fontSize="small"/>{profile.location}
                </Typography>
                <Divider/><br/>
                {social.map(network => (
                    <Link display="block"  rel="noopener" target="_blank" className={classes.sideBarDes} variant="body1" href={profile.github} key={network}>
                        <Grid container direction="row" spacing={1} alignItems="center">
                            <Grid item>
                                <network.icon />
                            </Grid>
                            <Grid item>
                                <Link
                                    variant="body2"
                                    color="primary"
                                    href={network.url}
                                    target="_blank"
                                >
                                    {network.name}
                                </Link>
                            </Grid>
                        </Grid>
                    </Link>
                ))}
            </Paper>
        </Grid>
    );
}

Sidebar.propTypes = {
    archives: PropTypes.array,
    description: PropTypes.string,
    social: PropTypes.array,
    title: PropTypes.string,
};